# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import logging
import hashlib
import hmac
import os
from datetime import datetime

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Shared secret for webhook signature verification
WEBHOOK_SECRET = os.environ.get("WEBHOOK_SECRET", "")


def verify_webhook_signature(payload_body, signature_header):
    """Verify the webhook payload signature from the partner."""
    if not WEBHOOK_SECRET:
        logger.warning("WEBHOOK_SECRET not configured - skipping signature verification")
        return True

    if not signature_header:
        return False

    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode("utf-8"),
        payload_body.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    return hmac.compare_digest(f"sha256={expected_signature}", signature_header)


def process_user_action(action):
    """Process a single user action from the webhook payload."""
    action_type = action.get("type")
    user_id = action.get("user_id")
    timestamp = action.get("timestamp")
    metadata = action.get("metadata", {})

    if not action_type or not user_id:
        raise ValueError(f"Invalid action: missing required fields. Got: {action.keys()}")

    logger.info(
        "Processing action: type=%s, user_id=%s, timestamp=%s",
        action_type,
        user_id,
        timestamp,
    )

    result = {
        "action_type": action_type,
        "user_id": user_id,
        "processed_at": datetime.utcnow().isoformat(),
        "status": "processed",
    }

    if action_type == "user_signup":
        result["details"] = f"New user signup processed for {user_id}"
    elif action_type == "purchase":
        amount = metadata.get("amount", 0)
        currency = metadata.get("currency", "USD")
        result["details"] = f"Purchase of {amount} {currency} recorded for {user_id}"
    elif action_type == "profile_update":
        updated_fields = metadata.get("updated_fields", [])
        result["details"] = f"Profile fields updated: {updated_fields}"
    elif action_type == "user_deactivation":
        result["details"] = f"User {user_id} deactivation processed"
    else:
        result["status"] = "unrecognized"
        result["details"] = f"Unrecognized action type: {action_type}"

    return result


def lambda_handler(event, context):
    """
    AWS Lambda handler for processing webhook events from external partners.
    Triggered by API Gateway.
    """
    try:
        # Extract signature for verification
        headers = event.get("headers", {}) or {}
        signature = headers.get("x-webhook-signature", headers.get("X-Webhook-Signature"))

        # Get the raw body from API Gateway
        body = event.get("body", "")

        if not body:
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Empty request body"}),
            }

        # Verify webhook signature
        if not verify_webhook_signature(body, signature):
            logger.warning("Invalid webhook signature received")
            return {
                "statusCode": 401,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Invalid webhook signature"}),
            }

        # Safely deserialize JSON (NOT pickle - never use pickle with untrusted data)
        if event.get("isBase64Encoded", False):
            import base64
            body = base64.b64decode(body).decode("utf-8")

        try:
            payload = json.loads(body)
        except json.JSONDecodeError as e:
            logger.error("Invalid JSON in request body: %s", str(e))
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Invalid JSON payload"}),
            }

        # Validate payload structure
        if not isinstance(payload, dict):
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Payload must be a JSON object"}),
            }

        # Extract and process user actions
        actions = payload.get("actions", [])
        partner_id = payload.get("partner_id", "unknown")
        event_id = payload.get("event_id", "unknown")

        if not isinstance(actions, list):
            actions = [actions]

        logger.info(
            "Received webhook: event_id=%s, partner_id=%s, action_count=%d",
            event_id,
            partner_id,
            len(actions),
        )

        results = []
        errors = []

        for i, action in enumerate(actions):
            try:
                if not isinstance(action, dict):
                    errors.append({"index": i, "error": "Action must be a JSON object"})
                    continue
                result = process_user_action(action)
                results.append(result)
            except (ValueError, KeyError) as e:
                logger.error("Error processing action %d: %s", i, str(e))
                errors.append({"index": i, "error": str(e)})

        response_body = {
            "event_id": event_id,
            "processed": len(results),
            "errors": len(errors),
            "results": results,
        }

        if errors:
            response_body["error_details"] = errors

        status_code = 200 if not errors else 207  # 207 Multi-Status if partial errors

        return {
            "statusCode": status_code,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps(response_body),
        }

    except Exception as e:
        logger.exception("Unexpected error processing webhook: %s", str(e))
        return {
            "statusCode": 500,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": "Internal server error"}),
        }